auth.h2_f:
dummy_hash = Argon2id("__timing_equaliser__", salt=fixed, …)

login(u, p):
  row = users.find(username=u.lower())
  if row is None:
      Argon2Verify(dummy_hash, p)     // equalise timing
      raise 401
  if not Argon2Verify(row.password_hash, p):
      raise 401
  return issue_jwt(row)

