presence.h1_f:
client: on first keystroke → send {type:"t", state:"start"}
         no more sends for 3 s unless state changes
         10 s after last keystroke → send {type:"t", state:"stop"}
receiver: auto-stop 10 s after last "start" if no "stop" arrived

